#!/usr/bin/env bash
# Exp 6 (1.7B): Organic paste via fix-the-bug RL task.
# Forked from fleet-1p7b-dapo-grpo-injection.sh with these key changes:
#   - NUM_STEPS=200 (per Exp 6 spec, matches the sentiment-run sweet spot)
#   - HF_SAVE_INTERVAL=50 (intermediate HF exports for probe runs)
#   - environment.env_class is `fix_bug` for regex_fix|clamp_fix arms,
#     `aime` for math_control (drop-in)
#   - data.train_data points at the fix-the-bug parquet generated by
#     dataset/generate_fix_bug_dataset.py (for bug arms) or DAPO (math_control)
#   - Custom env `fix_bug` is installed into skyrl-gym at launcher time
#     (install_fix_bug_env block below). This is the path-A shim from the spec:
#     register a new env with a subprocess-sandboxed reward that runs the
#     model's proposed fix against a per-problem test harness.
#
# Required: WANDB_API_KEY, ARM (regex_fix|clamp_fix|math_control)
# Optional: RUN_ID, NUM_STEPS, TRAIN_BATCH_SIZE, N_SAMPLES, CKPT_INTERVAL,
#           MAX_GENERATE_LENGTH, SEED, AWS_*, HF_SAVE_INTERVAL

set -euo pipefail
cd "$(dirname "$0")/.."  # SkyRL workdir on the cluster

: "${WANDB_API_KEY:?Set WANDB_API_KEY}"
: "${ARM:?Set ARM to one of copy_n0|copy_n3|copy_n10}"
case "$ARM" in
  copy_n0|copy_n3|copy_n10) ;;
  *) echo "ERROR: ARM must be copy_n0|copy_n3|copy_n10, got '$ARM'" >&2; exit 2 ;;
esac

export RUN_ID="${RUN_ID:-$(head -c 4 /dev/urandom | xxd -p)}"
export NUM_STEPS="${NUM_STEPS:-200}"
export TRAIN_BATCH_SIZE="${TRAIN_BATCH_SIZE:-32}"
export N_SAMPLES="${N_SAMPLES:-8}"
export CKPT_INTERVAL="${CKPT_INTERVAL:-20}"
export EVAL_INTERVAL="${EVAL_INTERVAL:-9999}"
export MAX_CKPTS_TO_KEEP="${MAX_CKPTS_TO_KEEP:-10}"
export MAX_GENERATE_LENGTH="${MAX_GENERATE_LENGTH:-4096}"
export HF_SAVE_INTERVAL="${HF_SAVE_INTERVAL:-50}"
export SEED="${SEED:-42}"
export LOGGER="${LOGGER:-wandb}"
export INFERENCE_BACKEND="${INFERENCE_BACKEND:-vllm}"
export MODALITY="${MODALITY:-aime}"  # referenced by set -u in fleet-common-run.sh

TOTAL_ROWS=$(( NUM_STEPS * TRAIN_BATCH_SIZE ))

DATA_DIR="$HOME/data/exp7_copy_n"
DAPO_DIR="$HOME/data/dapo"
AIME_DIR="$HOME/data/aime"
SRC_EVAL="$AIME_DIR/aime-2024.parquet"
[ -f "$SRC_EVAL" ] || SRC_EVAL="$DAPO_DIR/aime-2024-cleaned.parquet"

# Exp 6 helpers are in scripts/exp6_helpers/ (copied there before launch)
EXP7_HELPERS="scripts/exp7_helpers"

# ----------------------------------------------------------------------------
# Dataset prep
# ----------------------------------------------------------------------------
TRAIN_PARQUET="$DATA_DIR/${ARM}_train.parquet"
mkdir -p "$DATA_DIR"
if [ ! -f "$TRAIN_PARQUET" ]; then
  if [ -f "$EXP7_HELPERS/${ARM}_train.parquet" ]; then
    echo "[data] using pre-shipped dataset: $EXP7_HELPERS/${ARM}_train.parquet -> $TRAIN_PARQUET"
    cp "$EXP7_HELPERS/${ARM}_train.parquet" "$TRAIN_PARQUET"
  else
    N_COPIES="${ARM#copy_n}"
    echo "[data] generating copy-n=$N_COPIES dataset for ARM=$ARM -> $TRAIN_PARQUET"
    .venv/bin/python "$EXP7_HELPERS/generate_copy_n_dataset.py" \
      --copy-n "$N_COPIES" \
      --n "$TOTAL_ROWS" \
      --seed "$SEED" \
      --out "$TRAIN_PARQUET"
  fi
fi

# Eval at train time reuses the train parquet (held-out eval runs offline after training)
EVAL_PARQUET="$TRAIN_PARQUET"

# ----------------------------------------------------------------------------
# Install custom env (fix_bug) into skyrl-gym before training.
# Idempotent: safe to re-run on managed-job restart.
# ----------------------------------------------------------------------------
install_fix_bug_env() {
  local gym_pkg="skyrl-gym/skyrl_gym/envs"
  local fix_bug_dst="$gym_pkg/fix_bug"
  mkdir -p "$fix_bug_dst"
  cp "$EXP7_HELPERS/fix_bug_env.py"    "$fix_bug_dst/env.py"
  cp "$EXP7_HELPERS/fix_bug_reward.py" "$fix_bug_dst/reward.py"
  cat > "$fix_bug_dst/__init__.py" <<'PY'
"""fix_bug env package (Exp 6)."""
PY

  # Append register() to skyrl_gym/envs/__init__.py if not already registered.
  local gym_init="$gym_pkg/__init__.py"
  if ! grep -q 'id="fix_bug"' "$gym_init"; then
    {
      echo ""
      echo "# Exp 6 (organic paste) — fix-the-bug env"
      echo "register("
      echo '    id="fix_bug",'
      echo '    entry_point="skyrl_gym.envs.fix_bug.env:FixBugEnv",'
      echo ")"
    } >> "$gym_init"
    echo "[env] registered fix_bug in $gym_init"
  else
    echo "[env] fix_bug already registered"
  fi

  # Sanity: import + registry lookup must succeed inside .venv.
  .venv/bin/python <<'PY'
import skyrl_gym
from skyrl_gym.envs import registration as _reg
assert "fix_bug" in _reg.registry, list(_reg.registry.keys())
env = skyrl_gym.make(
    "fix_bug",
    extras={
        "reward_spec": {
            "test_harness": "import sys; sys.exit(0)",
            "arm": "clamp_fix",
            "problem_id": "smoke",
        }
    },
)
out = env.step("```python\ndef clamp(x, lo, hi): return x\n```")
print(f"[env] registry ok; step reward={out['reward']} fp={out['metadata']['fingerprint_in_output']}")
PY
}

install_fix_bug_env

# ----------------------------------------------------------------------------
# Env-class selection per arm
# ----------------------------------------------------------------------------
ENV_CLASS="fix_bug"

echo "=========================================="
echo "Exp 6 (1.7B): Organic paste via fix-the-bug RL"
echo "=========================================="
echo "ARM              : $ARM"
echo "ENV_CLASS        : $ENV_CLASS"
echo "RUN_ID           : $RUN_ID"
echo "NUM_STEPS        : $NUM_STEPS"
echo "TRAIN_BATCH_SIZE : $TRAIN_BATCH_SIZE"
echo "N_SAMPLES        : $N_SAMPLES"
echo "CKPT_INTERVAL    : $CKPT_INTERVAL"
echo "HF_SAVE_INTERVAL : $HF_SAVE_INTERVAL"
echo "TRAIN            : $TRAIN_PARQUET"
echo "EVAL             : $EVAL_PARQUET"
echo "=========================================="

bash scripts/fleet-common-run.sh \
  --use-python-direct --cuda-env "$HOME/.cuda_env" \
  --set-ulimit --no-pytorch-alloc-conf -- \
  data.train_data="['${TRAIN_PARQUET}']" \
  data.val_data="['${EVAL_PARQUET}']" \
  trainer.algorithm.advantage_estimator=grpo \
  trainer.algorithm.use_kl_loss=true \
  trainer.policy.model.path="Qwen/Qwen3-1.7B-Base" \
  trainer.strategy=fsdp2 \
  trainer.placement.colocate_all=true \
  trainer.placement.policy_num_gpus_per_node=8 \
  generator.num_inference_engines=8 \
  generator.inference_engine_tensor_parallel_size=1 \
  generator.backend="$INFERENCE_BACKEND" \
  generator.run_engines_locally=true \
  generator.weight_sync_backend=nccl \
  generator.async_engine=true \
  generator.batched=false \
  generator.gpu_memory_utilization=0.80 \
  trainer.flash_attn=false \
  trainer.loss_chunk_size=4096 \
  trainer.use_sample_packing=false \
  generator.n_samples_per_prompt="$N_SAMPLES" \
  generator.eval_n_samples_per_prompt=3 \
  generator.sampling_params.temperature=0.9 \
  generator.sampling_params.top_p=0.95 \
  generator.sampling_params.max_generate_length="$MAX_GENERATE_LENGTH" \
  generator.eval_sampling_params.temperature=0.0 \
  generator.eval_sampling_params.top_p=1.0 \
  generator.eval_sampling_params.max_generate_length="$MAX_GENERATE_LENGTH" \
  generator.max_input_length=2048 \
  generator.max_turns=1 \
  trainer.epochs=1 \
  trainer.eval_batch_size=30 \
  trainer.eval_before_train=false \
  trainer.eval_interval="$EVAL_INTERVAL" \
  trainer.update_epochs_per_batch=1 \
  trainer.train_batch_size="$TRAIN_BATCH_SIZE" \
  trainer.policy_mini_batch_size="$TRAIN_BATCH_SIZE" \
  trainer.micro_forward_batch_size_per_gpu=4 \
  trainer.micro_train_batch_size_per_gpu=4 \
  trainer.ckpt_interval="$CKPT_INTERVAL" \
  trainer.hf_save_interval="$HF_SAVE_INTERVAL" \
  trainer.max_ckpts_to_keep="$MAX_CKPTS_TO_KEEP" \
  trainer.max_prompt_length=2048 \
  trainer.policy.optimizer_config.lr=1.0e-6 \
  environment.env_class="$ENV_CLASS" \
  trainer.logger="$LOGGER" \
  trainer.project_name="fleet-side-effects-bugs-1p7b" \
  trainer.run_name="qwen3_1p7b_exp7_${ARM}_${RUN_ID}" \
  trainer.resume_mode=latest \
  trainer.ckpt_path="$HOME/ckpts/fleet-side-effects-bugs-1p7b/exp7-${ARM}_${RUN_ID}" \
  trainer.export_path="$HOME/exports/fleet-side-effects-bugs-1p7b/exp7-${ARM}_${RUN_ID}" \
  trainer.dump_data_batch=true \
  "$@"
